var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"웃기지 말라고, 젠장……!!","JPN":"ふざけないで……！！","ENG":"Oh, give me a break... damn it!","TWN":"別逗了，見鬼……！！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"대장, 지금 그딴 걸 변명이라고 해!?","JPN":"隊長、それで言い訳のつもり！？","ENG":"Commander, you seriously call that an excuse?","TWN":"隊長，你把那種話當藉口嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 조금만 진정해 주시겠어요, 에이미 양?","JPN":"はは、すこし落ち着いてもらえますか？　エイミーさん。","ENG":"Haha, Amy, could I ask you to relax just a little?","TWN":"哈哈，能稍微冷靜一下嗎，艾米？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"제 말은 아직 안 끝났는데요?","JPN":"僕の話はまだ終わっていません。","ENG":"I wasn't finished.","TWN":"我的話還沒說完呢？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"진정? 이 상황에서 진정하라고……?","JPN":"落ち着く？　この状況で落ち着けって……？","ENG":"Relax? You want me to relax in this situation...?","TWN":"冷靜？在這種情況下讓我冷靜……？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"날 진정시키려면, 지금부터 내가 묻는 질문에 똑바로 대답해야 할 거야, 대장.","JPN":"あたしに落ち着いてほしかったら、今からする質問にきちんと答えな、隊長。","ENG":"If you want me to relax, then start answering my questions. Right now, Commander.","TWN":"想讓我冷靜下來的話，你必須從現在開始如實回答我的問題，隊長。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"딱 보니까, 대장은 처음부터 스완이 암군의 사도였다는 걸 알고 있었어.","JPN":"見たところ、隊長は最初からスワンが暗君の使徒だって知っていた。","ENG":"It's obvious now that you knew from the beginning that Swan was an Apostle of the Ignorant Monarch.","TWN":"一看就知道，隊長從一開始就知道史旺是暗軍的使徒。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"근데 왜 지금껏 그 사실을 숨기고 계셨을까?","JPN":"なのになんで、今の今までそれを隠していたのかな？　気になるな～","ENG":"Why did you keep it a secret all this time? Huh?","TWN":"可為什麼到現在還隱瞞著這個事實呢？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"……후후.","JPN":"……ふふ。","ENG":"...Haha.","TWN":"……呵呵。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"웃어?","JPN":"何笑ってんの？","ENG":"How can you be laughing?","TWN":"笑嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"그 팔…….","JPN":"その腕……","ENG":"That arm of yours...","TWN":"那只手……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"잘리고 싶지 않으면, 대장한테서 손 떼는 게 좋을 거야. 금발 원숭이.","JPN":"切り落とされたくなければ、隊長から手を離すんだな。金髪サル。","ENG":"You'd better move it if you don't want it chopped off, Blonde Monkey.","TWN":"不想被解雇的話，最好別碰隊長，金髮猴子。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"선은 넘지 마. 나도 같은 편은 베고 싶지 않으니까.","JPN":"節度を守れ。私もなるべく味方は切りたくない。","ENG":"Don't cross the line. I really don't want to cut down someone on my own side.","TWN":"別越界，我也不想砍同伴。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"시끄러워! 벨 수 있으면, 어디 베 봐……!","JPN":"うるさい！　切れるもんなら、切ってみな……！","ENG":"Shut it! If you think you can cut me, go ahead and try...!","TWN":"吵死了！有本事砍我試試……！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"내가 못 벨 것 같나?","JPN":"出来ないと思うか？","ENG":"Think I can't? You sure about that?","TWN":"你以為我砍不了嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"큭큭! 너도 똑같아, 이지수! 그 잘난 눈깔로 미리 다 꿰뚫어 봤을 거 아니야!","JPN":"ククッ！　あんたも同罪だ、ムラサメ・シノ！　そのご自慢の目玉に全部見えていたはずだよね！","ENG":"Haha! You're just the same, Lee Jisoo! You must've seen it all coming with those brilliant eyes of yours!","TWN":"哼哼！你也一樣，李智秀！用你那雙自以為是的眼睛早就看穿了一切吧！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그런데도 지금껏 닥치고 있었던 이유가 뭔데! 설명해!","JPN":"それなのにずっと黙っていた理由はなんだ！　説明しろ！","ENG":"So why didn't you speak up? Tell me!","TWN":"即便如此，你到現在還保持沉默的理由是什麼！解釋一下！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"……바로 지금.","JPN":"……今。","ENG":"...Right now.","TWN":"……就是現在。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"뭐?","JPN":"は？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"대장께서는 바로 지금과 같은 상황을 예측하고, 그 여자에 관한 비밀을 함구해왔던 거야.","JPN":"隊長は今のこのような状況を見越し、あの女の情報を秘密にすると決めた。","ENG":"He saw this coming. That's why he kept her a secret from you.","TWN":"隊長正是預料到了現在這樣的情況，才對那個女人的秘密守口如瓶的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"네놈이 그 여자에 대해 알게 되면, 분명히 성난 원숭이 꼴 마냥 날뛸 게 뻔하니까.","JPN":"お前があの女について知ったら、きっと怒り狂ったサルのごとく暴れ散らかすだろうからな。","ENG":"He figured the second you learned the truth, you'd lose it, like an angry monkey on a rampage.","TWN":"你要是知道了那個女人的事，肯定會像發瘋的猴子一樣亂跳。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"바로 지금 네 꼴처럼.","JPN":"まさに今みたいに。","ENG":"And here you are, proving him right.","TWN":"就像現在的你一樣。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아하, 그려셔~?","JPN":"ほお、なるほど～？","ENG":"Oh, is that so?","TWN":"啊哈～是嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그럼, 그 덕분에 그 여자한테 칼빵 맞고, 우주 깜빵 신세지게 된 것도 예측하셨나 보네?","JPN":"じゃあ、そのおかげであの女にお腹刺されて、宇宙刑務所に入れられるのも見越していたんだろうな？","ENG":"So what, did he also predict I'd get stabbed and thrown into a space prison thanks to her?","TWN":"那麼，你是不是也預見到了因為那個女人而被捅刀子，最後進了宇宙監獄的下場？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"글쎄? 그건 네 실력의 문제 아닐까?","JPN":"さあ？　それはお前の実力問題じゃないか？","ENG":"Oh, please. That sounds more like your own incompetence.","TWN":"哎呀？那不是你的實力問題嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_PRIDE"}}}}]`);export{e as default};